from flask import Flask, request
import pandas as pd
from tensorflow import keras
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Conv2D, Flatten
from tensorflow.keras.optimizers import Adam
from tensorflow.keras.preprocessing.image import ImageDataGenerator
import numpy as np
import cv2

app = Flask(__name__)
model_path = "model.h5"  # Assumes model is saved here
img_size = 100
batch_size = 32

# Load or train your model
def load_or_train_model():
    try:
        return keras.models.load_model(model_path)
    except OSError:  # Model doesn't exist yet
        model = Sequential([
            Conv2D(64, (3, 3), activation='relu', input_shape=(img_size, img_size, 3)),
            MaxPooling2D(pool_size=(2, 2)),
            Flatten(),
            Dense(100, activation='relu'),
            Dropout(0.5),
            Dense(1, activation='sigmoid')
        ])

        model.compile(loss='binary_crossentropy', optimizer=Adam(), metrics=['accuracy'])
        
        return model

@app.route('/train', methods=['POST'])
def train():
    if 'file' not in request.files:
        return "No file part"
    
    file = request.files['file']
    dataframe = pd.read_csv(file)  # Assume CSV files have labels
    X = []
    y = []

    for i, row in dataframe.iterrows():
        img = cv2.imread('./images/' + row['image_name'])
        img = cv2.resize(img, (img_size, img_size))
        X.append(img)
        y.append(row['label'])  # Assumes 'label' is the column with labels in CSV files
        
    X = np.array(X)
    y = np.array(y)
    
    model = load_or_train_model()
    datagen = ImageDataGenerator(rescale=1./255, rotation_range=40, width_shift_range=0.2, height_shift_range=0.2, horizontal_flip=True)
    
    # Train the model with data augmentation and validation split for better performance
    datagen.fit(X)
    model.fit(datagen.flow(X, y), epochs = 30, validation_split=0.2 ) 
    model.save(model_path)
    
    return "Training done", 201